        const freq = {};
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            freq[num] = (freq[num] || 0) + 1;
        }
        let maxCount = -1;
        let res = -1;
        for (const key in freq) {
            const count = freq[key];
            if (count >= t) {
                if (count > maxCount || (count === maxCount && key < res)) {
                    maxCount = count;
                    res = key;
                }
            }
        }
        ans.push(res);
    }
    return ans;
}
